values.content:
Write an SEO blog article for CMCA Finance based on this source material:

Title: {{ $json.TITLE }}
Source URL: {{ $json.URL }}
Date: {{ $json.date }}

SOURCE CONTENT:
{{ $json.CONTENT }}

parameters.jsCode:
const articleData = $input.first().json;

const now = new Date();
const formatter = new Intl.DateTimeFormat('en-CA', {
  timeZone: 'America/Toronto',
  year: 'numeric', month: '2-digit', day: '2-digit',
  hour: '2-digit', minute: '2-digit', hour12: false,
});
const parts = formatter.formatToParts(now);
const get = (type) => parts.find(p => p.type === type).value;

return [{
  json: {
    date: `${get('year')}-${get('month')}-${get('day')}`,
    time: `${get('hour')}:${get('minute')}`,
    CONTENT: articleData.CONTENT || '',
    TITLE: articleData.TITLE || '',
    URL: articleData.URL || '',
    row_number: articleData.row_number || null,
    DATE_PUBLISHED: articleData['DATE PUBLISHED'] || '',
  },
  pairedItem: { item: 0 }
}];

const items = $input.all();

const filtered = items.filter(item => {
  const row = item.json;

  return (
    row["ADMIN ACTION"] === "Approve" &&
    (!row["STATUS LOG"] ||
    row["STATUS LOG"].trim() === "" ||
    row["STATUS LOG"].toLowerCase().startsWith("rejected") ||
    row["STATUS LOG"].toLowerCase() === "ready for review") &&
    (!row["LINK TO GOOGLE DOC"] || row["LINK TO GOOGLE DOC"].trim() === "") &&
    (!row["LINK TO WORDPRESS BACKEND"] || row["LINK TO WORDPRESS BACKEND"].trim() === "")
  );
});

return filtered;

// Get the HTTP response (may be empty if fetch failed/timed out)
const httpResponse = $input.first();
const html = (httpResponse.json.data || httpResponse.json.body || "");

// Get original sheet data from the loop node
const originalData = $('Loop Over Items: APPROVED').item.json;

let cleanContent = "";

// --- Try to use fetched HTML first ---
if (html && html.length >= 100) {
  let cleaned = html
    .replace(/<script[\s\S]*?<\/script>/gi, "")
    .replace(/<style[\s\S]*?<\/style>/gi, "")
    .replace(/<nav[\s\S]*?<\/nav>/gi, "")
    .replace(/<header[\s\S]*?<\/header>/gi, "")
    .replace(/<footer[\s\S]*?<\/footer>/gi, "")
    .replace(/<aside[\s\S]*?<\/aside>/gi, "")
    .replace(/<figure[\s\S]*?<\/figure>/gi, "");

  const articleMatch = cleaned.match(/<article[\s\S]*?<\/article>/i);
  if (articleMatch) cleaned = articleMatch[0];

  cleaned = cleaned
    .replace(/<[^>]+>/g, " ")
    .replace(/&nbsp;/g, " ")
    .replace(/&amp;/g, "&")
    .replace(/&lt;/g, "<")
    .replace(/&gt;/g, ">")
    .replace(/&#39;/g, "'")
    .replace(/&quot;/g, '"')
    .replace(/\s+/g, " ")
    .trim();

  if (cleaned.length >= 200) {
    cleanContent = cleaned.substring(0, 4000);
  }
}

// --- Fallback: use existing CONTENT from the sheet (written by P0) ---
if (!cleanContent || cleanContent.length < 200) {
  const sheetContent = originalData.CONTENT || "";
  const stripped = sheetContent
    .replace(/<[^>]+>/g, " ")
    .replace(/\s+/g, " ")
    .trim();

  if (stripped.length >= 200) {
    cleanContent = stripped.substring(0, 4000);
  }
}

// --- If still no usable content, flag as failed ---
// IMPORTANT: pairedItem: {item: 0} preserves the chain so downstream nodes
// can correctly resolve $('Extract Article Text').item across all loop cycles
if (!cleanContent || cleanContent.length < 100) {
  return [{ json: { ...originalData, _extractFailed: true }, pairedItem: { item: 0 } }];
}

// --- Return with usable content ---
return [{
  json: {
    ...originalData,
    _extractFailed: false,
    CONTENT: cleanContent
  },
  pairedItem: { item: 0 }
}];

values.content:
=Here is the draft article to refine:

Title: {{ $json.title }}
Slug: {{ $json.slug }}
Category: {{ $json.category }}
Meta Description: {{ $json.meta_description }}

DRAFT ARTICLE (plain text):
{{ $json.content }}

parameters.jsCode:
const item = $input.first().json;

// Support both OpenAI node output formats:
// typeVersion 1.x (Chat Completions): item.message.content
// typeVersion 2.x (Responses API):    item.output[0].content[0].text
let article = {};

if (item.message && item.message.content) {
  // typeVersion 1.x — already a parsed object when jsonOutput: true
  article = item.message.content;
} else if (item.output && item.output[0] && item.output[0].content && item.output[0].content[0]) {
  const raw = item.output[0].content[0].text;
  if (typeof raw === 'string') {
    try {
      article = JSON.parse(raw);
    } catch (e) {
      // Model returned plain text instead of JSON (e.g. greeting, refusal, or incomplete response)
      article = { error: 'invalid_response' };
    }
  } else {
    // Already a parsed object (jsonOutput: true auto-parsed it)
    article = raw || {};
  }
}

return [{
  json: {
    title:            article.title            || '',
    slug:             article.slug             || '',
    content:          article.content          || '',
    wp_content:       article.wp_content       || '',
    category:         article.category         || '',
    meta_description: article.meta_description || '',
    _firstPassError:  article.error            || null
  }
}];
